//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String typings;
    Scripts scripts;
    Repository repository;
    List<String> files;
    List<String> keywords;
    String author;
    String license;
    Bugs bugs;
    String homepage;
    DevDependencies devDependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.typings,
        required this.scripts,
        required this.repository,
        required this.files,
        required this.keywords,
        required this.author,
        required this.license,
        required this.bugs,
        required this.homepage,
        required this.devDependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        typings: json["typings"],
        scripts: Scripts.fromJson(json["scripts"]),
        repository: Repository.fromJson(json["repository"]),
        files: List<String>.from(json["files"].map((x) => x)),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        author: json["author"],
        license: json["license"],
        bugs: Bugs.fromJson(json["bugs"]),
        homepage: json["homepage"],
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "typings": typings,
        "scripts": scripts.toJson(),
        "repository": repository.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "author": author,
        "license": license,
        "bugs": bugs.toJson(),
        "homepage": homepage,
        "devDependencies": devDependencies.toJson(),
    };
}

class Bugs {
    String url;

    Bugs({
        required this.url,
    });

    factory Bugs.fromJson(Map<String, dynamic> json) => Bugs(
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "url": url,
    };
}

class DevDependencies {
    String coveralls;
    String documentation;
    String flowBin;
    String nyc;
    String prettier;

    DevDependencies({
        required this.coveralls,
        required this.documentation,
        required this.flowBin,
        required this.nyc,
        required this.prettier,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        coveralls: json["coveralls"],
        documentation: json["documentation"],
        flowBin: json["flow-bin"],
        nyc: json["nyc"],
        prettier: json["prettier"],
    );

    Map<String, dynamic> toJson() => {
        "coveralls": coveralls,
        "documentation": documentation,
        "flow-bin": flowBin,
        "nyc": nyc,
        "prettier": prettier,
    };
}

class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}

class Scripts {
    String test;
    String flow;
    String lint;
    String lintCheck;
    String prettier;
    String testonly;
    String testdocs;
    String docs;
    String travis;

    Scripts({
        required this.test,
        required this.flow,
        required this.lint,
        required this.lintCheck,
        required this.prettier,
        required this.testonly,
        required this.testdocs,
        required this.docs,
        required this.travis,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
        flow: json["flow"],
        lint: json["lint"],
        lintCheck: json["lint-check"],
        prettier: json["prettier"],
        testonly: json["testonly"],
        testdocs: json["testdocs"],
        docs: json["docs"],
        travis: json["travis"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
        "flow": flow,
        "lint": lint,
        "lint-check": lintCheck,
        "prettier": prettier,
        "testonly": testonly,
        "testdocs": testdocs,
        "docs": docs,
        "travis": travis,
    };
}
